        WHAT_IS_WRONG_WITH_THAT_GIRL_OH_SHE                                  = 6983,  -- What is wrong with that girl? Oh, she's probably just excited to see her father after all this time.
        OH_YOU_RE_THE_ONE_FROM_THE_PIER                                      = 6984,  -- Oh, you're the one from the pier... I must apologize about my mother.
        MY_FATHER_WAS_A_SAILOR_NO_ONE_HAS                                    = 6985,  -- My father was a sailor... No one has seen him or his ship for over a year. People are saying the pirates got him.
        MY_MOTHER_HAS_TO_MOVE_ON_IF_ONLY                                     = 6986,  -- My mother has to move on... If only she could be convinced that Father won't be coming back...
