        REALLY_OH_THANK_YOU                                                  = 6990,  -- Really? Oh, thank you!
        THERE_S_SOMETHING_THAT_FATHER_TOLD_ME_ONCE                           = 6991,  -- There's something that Father told me once that might help us. He said that the % he wore was very rare.
        AND_I_RECENTLY_MET_A_SAILOR_WHO_SAID                                 = 6992,  -- And I recently met a sailor who said he saw a pirate wearing one!
        COULD_YOU_BRING_ME_THAT_IF_IT_IS                                     = 6993,  -- Could you bring me that %? If it is really Father's...I think Mother and I can finally move on.
        PLEASE_TAKE_BACK_FATHER_S_FROM_THAT_PIRATE                           = 6994,  -- Please! Take back Father's % from that pirate!
        I_SEE_IF_YOU_EVER_CHANGE_YOUR_MIND                                   = 6995,  -- I see... If you ever change your mind...I'll be here.
        YOU_YOU_GOT_IT_SO_THE_PIRATES_REALLY                                 = 6996,  -- You... You got it. So the pirates really...
        I_VE_THOUGHT_LONG_AND_HARD_SINCE_WE                                  = 6997,  -- I've thought long and hard since we last spoke, and I've decided to stand by Mother's side and believe in Father's return.
