        MOTHER_PLEASE_LISTEN_TO_ME                                           = 7005,  -- Mother, please! Listen to me!
        ID_7006                                                              = 7006,  -- ...
        EVEN_IF_A_PIRATE_HAD_THIS_IT_DOESN                                   = 7007,  -- Even if a pirate had this, it doesn't necessarily mean Father's gone!
        I_LL_BELIEVE_I_LL_WAIT_WITH_YOU                                      = 7008,  -- I'll believe... I'll wait with you. So please, don't close your eyes on reality.
