        BOARD_THE_SHIP_YES_PLEASE_NOT_RIGHT_NOW                              = 7126,  -- Board the ship? Yes, please. Not right now.
        THANK_YOU_GO_RIGHT_ON_THROUGH                                        = 7127,  -- Thank you. Go right on through.
        I_M_SORRY_BUT_YOU_DON_T_SEEM                                         = 7128,  -- I'm sorry, but you don't seem to have enough gil.
        AH_YOU_MUST_BE_MR_MS_WE_VE                                           = 7129,  -- Ah, you must be Mr./Ms.] %. We've been expecting you. Mr. Rycharde has already paid your fare. Please go on through.
        THIS_IS_THE_IMMIGRATION_COUNTER_PLEASE_GO_TO                         = 7130,  -- This is the immigration counter. Please go to the counter on the other side if you wish to board a ship.
