        THE_SELBINA_FERRY_WILL_ARRIVE_SOON_PLEASE_WAIT                       = 7132,  -- The Selbina ferry will arrive soon. Please wait here.
        THE_SHIP_TO_AL_ZAHBI_WILL_ARRIVE_SOON                                = 7133,  -- The ship to Al Zahbi will arrive soon.
        THE_SHIP_BOUND_FOR_SELBINA_WILL_ARRIVE_SHORTLY                       = 7134,  -- The ship bound for Selbina will arrive shortly.
