        BUT_OF_COURSE_I_SHALL_NOT_SIMPLY_TAKE                                = 7748,  -- But of course, I shall not simply take without giving something in return. Let this be known to no one, but we at the Brugaire Consortium recently came into the possession of extravagant armor and apparel from the Near East. I may be able to make some...special arrangements...if you lend your assistance.
        O_ILLUSTRIOUS_ADVENTURER_PLEASE_ACCEPT_MY_PLEA                       = 7749,  -- O illustrious adventurer, please accept my plea!
        I_HAVE_HEARD_THAT_THE_BLACK_CREATURES_RESIDE                         = 7750,  -- I have heard that the black creatures reside in two places: at the top of an illuminated tower and at the bottom of a dark abyss. It also seems that there are two types: one that crawls on four legs and one that floats in the air. All I require is a segment from one of them. I implore you, please lend me your aid!
        TH_THIS_IS_UNDENIABLY_A_FRAGMENT_OF_THE                              = 7751,  -- Th-this is undeniably a fragment of the legendary Ultima! Kamaal! You must see this, Kamaal!
        YOU_FOOL_I_ONLY_NEED_TO_BE_CALLED                                    = 7752,  -- You fool! I only need to be called once. I do have ears!
        SHOW_IT_TO_ME                                                        = 7753,  -- Show it to me.
        TH_THIS_IS_ARTIFICIAL_SKIN_AND_AN_ARTIFICIAL                         = 7754,  -- Th-this is...artificial skin!? And an artificial frame, too... This is a segment taken from Ultima, without question.
        ADVENTURER_YOU_HAVE_MY_GRATITUDE_THE_RESTORATION_PROJECT             = 7755,  -- Adventurer, you have my gratitude. The restoration project in my homeland will be able to move into new research now, thanks to you.
        IN_THE_NEAR_FUTURE_OUR_NATION_MAY_NEED                               = 7756,  -- In the near future, our nation may need the help of distinguished adventurers such as yourself. I hope to see you again in my homeland, then.
        RIFAQAT_GIVE_THIS_GENTLEMAN_HIS_LADY_HER_REWARD                      = 7757,  -- Rifaqat. Give this gentleman his/lady her] reward. I think he/she] will be most pleased.
        THE_MOST_SKILLED_CLOTHCRAFTERS_IN_AHT_URHGAN_WEAVED                  = 7758,  -- The most skilled clothcrafters in Aht Urhgan weaved this over a span of ten years. It is a gift of utmost quality...and I humbly present it to you.
        IF_YOU_ACQUIRE_ANY_MORE_SEGMENTS_OF_ULTIMA                           = 7759,  -- If you acquire any more segments of Ultima, I would greatly appreciate it if you could bring them to me.
        ANOTHER_SEGMENT_FROM_ULTIMA_YOU_HAVE_MY_UTMOST                       = 7760,  -- Another segment from Ultima! You have my utmost gratitude. Please accept this in return.
        TH_THIS_IS_UNDENIABLY_A_FRAGMENT_OF_THE_2                            = 7761,  -- Th-this is undeniably a fragment of the legendary Omega! Hadiyah! You must see this, Hadiyah!
        INSOLENT_FOOL_WHO_GAVE_YOU_THE_RIGHT_TO                              = 7762,  -- Insolent fool! Who gave you the right to speak my name? Have you no idea who I am? I am a blue mage! You must show proper respect around me!
        HURRY_UP_AND_SHOW_ME_WHAT_YOU_HAVE                                   = 7763,  -- Hurry up and show me what you have, you blithering milksop!
        THIS_IT_IS_ALL_ARTIFICIAL_THE_FLESH_THE                              = 7764,  -- This... It is all artificial! The flesh...the blood...marvelous! This is most certainly a segment of Omega!
        MAY_YOUR_NAME_BE_PRAISED_ADVENTURER_WITH_THIS                        = 7765,  -- May your name be praised, adventurer! With this, restoration of the light divinity shall proceed in leaps and bounds!
        IT_APPEARS_THAT_THESE_ADVENTURERS_ARE_EVEN_MORE                      = 7766,  -- It appears that these adventurers are even more remarkable than I have heard. I would very much appreciate it if you would come to visit our great nation someday!
        RIFAQAT_GET_OFF_YOUR_TAIL_AND_GIVE_THIS                              = 7767,  -- Rifaqat, get off your tail and give this adventurer his/her] reward, now! Let us hope he/she] finds it most useful on his/her] adventures.
        THE_MOST_SKILLED_ARMORERS_IN_AHT_URHGAN_FORGED                       = 7768,  -- The most skilled armorers in Aht Urhgan forged this over a span of ten years. It is a gift of utmost quality...and I humbly present it to you.
        IF_YOU_ACQUIRE_ANY_MORE_SEGMENTS_OF_OMEGA                            = 7769,  -- If you acquire any more segments of Omega, I would greatly appreciate it if you could bring them to me.
        ANOTHER_SEGMENT_FROM_OMEGA_YOU_HAVE_MY_UTMOST                        = 7770,  -- Another segment from Omega! You have my utmost gratitude. Please accept this in return.
        YES_IT_S_UNMISTAKABLE_A_FRAGMENT_OF_OMEGA                            = 7771,  -- Yes...it's unmistakable. A fragment of Omega, and a far more ancient specimen than any we've encountered thus far!
        NOW_HADIYAH_WILL_HAVE_NO_CHOICE_BUT_TO                               = 7772,  -- Now, Hadiyah will have no choice but to recognize my efforts! Wilhelm's day has come, and it shall be a glorious one! Muahahahahahaha!
        AHEM_WORD_HAS_IT_THAT_THERE_ARE_OTHER                                = 7773,  -- <Ahem>... Word has it that there are other curious materials to be found in this otherworldly place. Deliver to me some samples along with this fragment, and I shall reward you with rare pieces of equipment from the Consortium's vaults.
        FURTHERMORE_SHOULD_YOU_ALREADY_POSSESS_ANY_PIECES_OF                 = 7774,  -- Furthermore, should you already possess any pieces of equipment from a previous transaction, I would encourage you to deliver them to me along with this segment.
        THE_CONSORTIUM_HAS_IN_ITS_EMPLOY_A_SMITH                             = 7775,  -- The Consortium has in its employ a smith of the highest renown. He shall work his genius upon your treasured possession.
        I_SEE_YOU_ARE_A_MAN_WOMAN_OF                                         = 7776,  -- I see you are a man/woman] of your word. As am I, my friend. Take this, for you have earned it many times over.
        WHY_THIS_IS_A_SEGMENT_OF_ULTIMA_AND                                  = 7777,  -- Why, this is...! A segment of Ultima, and one unlike any I have seen before! Wherever, pray tell, did you come upon this?
        AH_BUT_IT_MATTERS_NOT_WHAT_MATTERS_IS                                = 7778,  -- Ah, but it matters not. What matters is that Kamaal--that blustering blowhard--will finally be forced to show me some respect! Heh! Hah! Heahaheahehahyah!
        AHEM_WORD_HAS_IT_THAT_THERE_ARE_OTHER_2                              = 7779,  -- <Ahem>... Word has it that there are other curious materials to be found in this otherworldly place. Deliver to me some samples along with this fragment, and I shall reward you with rare pieces of equipment from the Consortium's vaults.
        FURTHERMORE_SHOULD_YOU_ALREADY_POSSESS_ANY_PIECES_OF_2               = 7780,  -- Furthermore, should you already possess any pieces of equipment from a previous transaction, I would encourage you to deliver them to me along with this segment.
        THE_CONSORTIUM_HAS_IN_ITS_EMPLOY_A_SMITH_2                           = 7781,  -- The Consortium has in its employ a smith of the highest renown. He shall work his genius upon your treasured possession.
        AH_EXACTLY_WHAT_I_HAD_HOPED_TO_SEE                                   = 7782,  -- Ah, exactly what I had hoped to see! The Consortium is ever grateful for your contributions, friend. Take this, and may it serve you well.
        MAURIRI_IS_MY_NAME_AND_SENDING_PARCELS_FROM                          = 7783,  -- Mauriri is my name, and sending parcels from Mhaura is my game.t
        LOOKING_FOR_A_DELIVERY_COMPANY_THAT_ISN_T                            = 7784,  -- Looking for a delivery company that isn't lamey-wame? The quality of my service puts Mauriri to shame!
