        YOU_DO_NOT_POSSESS_YOU_WERE_NOT_PERMITTED                            = 7786,  -- You do not possess %. You were not permitted to board the ship...
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                            = 7787,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
        DO_SOMETHING_KUPO_PORTER_SERVICE_BUY_A_STORAGE                       = 7788,  -- Do something, kupo? Porter service? Buy a storage slip. No, thank you.
        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                         = 7789,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                        = 7790,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                 = 7791,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
