        NOT_THAT_WE_MOOGLES_WOULD_OBJECT_TO_THAT                             = 7794,  -- Not that we moogles would object to that sort of donation, kupo.
        CHOOSE_THE_ITEM_YOU_WISH_TO_ENTRUST_THEN                             = 7795,  -- Choose the item you wish to entrust, then trade it to me along with a single storage slip. I will take the item and return the slip to you, marked with an invisible seal.
        INVISIBLE_TO_YOU_AT_LEAST_IT_S_PLAIN                                 = 7796,  -- Invisible to you, at least. It's plain as day to us moogles, so don't even think of trying to pull one over on us, kupo.
        WHEN_IT_COMES_TIME_TO_RETRIEVE_YOUR_ITEM                             = 7797,  -- When it comes time to retrieve your item, just trade to me a single storage slip--any slip--once again.
        I_WILL_PRESENT_YOU_WITH_A_LIST_OF                                    = 7798,  -- I will present you with a list of all the items currently in my care, and you may choose the one you wish to withdraw. Simple as that, kupo!
        WHAT_S_MORE_NO_ADDITIONAL_TRANSACTION_FEES_WILL                      = 7799,  -- What's more, no additional transaction fees will be incurred! Pretty generous of us for a change, no?
        NOW_I_BET_YOU_RE_WONDERING_WHAT_THE                                  = 7800,  -- Now I bet you're wondering what the catch is, kupo. So as not to disappoint you, there are a few!
        FOR_ONE_ANY_SIGNED_ITEMS_WILL_LOSE_THEIR                             = 7801,  -- For one, any signed items will lose their signatures if you store them with me.
        WHY_YOU_SAY_HEY_EVEN_WE_MOOGLES_AREN                                 = 7802,  -- Why, you say? Hey, even we moogles aren't perfect! It's better for both of us if you keep your most precious possessions close at hand, kupo.
        NOW_LISTEN_UP_BECAUSE_THERE_S_ANOTHER_CATCH                          = 7803,  -- Now listen up, because there's another catch, and it's a doozy.
        IF_YOU_LOSE_YOUR_STORAGE_SLIP_I_WON                                  = 7804,  -- If you lose your storage slip, I won't be able to return your item. Ever. No ifs, ands, or buts! No I'm sorry, Mister Porter Moogle, it'll never happen again! Rules are rules, kupo, and someone has to keep them.
