        SO_YOU_RE_EH_I_VE_EARD_MUCH                                          = 8062,  -- So you're %, eh? I've 'eard much 'bout ya.
        LET_S_GET_THE_SMALL_MATTER_OF_THE                                    = 8063,  -- Let's get the small matter of the % out of the way first. Here you go.
