        WELCOME_WELCOME_BACK_FOR_MORE                                        = 8185,  -- Welcome, welcome! Back for more?
        INQUIRE_ABOUT_WHAT_REWARDS_AMBUSCADE_NOTHING_IN_PARTICULAR           = 8186,  -- Inquire about what? Rewards. Ambuscade. Nothing in particular.
