        ABDHALJS_HAS_TASKED_ME_WITH_DELIVERING_THESE_MISSIVES                = 8188,  -- Abdhaljs has tasked me with delivering these missives and a listaru of rewards to any and all discerning adventurers.
        WHAT_WOULD_YOU_LIKE_TO_VIEW_ITEMS_TO                                 = 8189,  -- What would you like to view? Items to purchase with hallmarks. Items available for total hallmarks. Items to purchase with gallantry. Missives from Abdhaljs. Upgrades for %. Upgrades for %. Upgrades for %. Upgrades for %. Upgrades for %. Upgrades for %. About hallmarks and gallantry. Go back. Nothing for now.
