        I_REQUESTED_TO_BE_STATIONED_WATIONED_IN_JEUNO                        = 8214,  -- I requested to be stationed-wationed in Jeuno, but that incident with the cake batter must have left more than a physical stain on my records.
        I_MISS_BEING_HOME_WOME_WITH_YOU_YOUR                                 = 8215,  -- I miss being home-wome with you, your lovely %, and my veritable treasure trove of books. But guess what--I get to work with the almighty Abdhaljs! His tomes are legendary, so I know I'll be able to pull through.
        P_S_WHATEVER_YOU_DO_DO_NOT_OPEN                                      = 8216,  -- P.S. Whatever you do, do not open my Shantotto Scorches Selbina calendar.
