        AHH_IT_S_NICE_TO_SEE_YOU_GOOD                                        = 8238,  -- Ahh, it's nice to see you, good sir/lady]. I have received a new letter.
        UM_YOU_SEE                                                           = 8239,  -- Um, you see...
        THIS_LETTER_COMES_FROM_THE_GREATARU_MAGE_ABDHALJS                    = 8240,  -- This letter comes from the greataru mage Abdhaljs himself.
        HERE_YOU_MAY_FEEL_FREE_TO_GIVE_IT                                    = 8241,  -- Here, you may feel free to give it a read-wead.
        I_LOOK_FORWARD_TO_HELPING_YOU_WITH_ALL                               = 8242,  -- I look forward to helping you with all of your equipment needs!
        DEAREST_ADVENTURER_I_AM_PLEASED_TO_HEAR_THAT                         = 8243,  -- Dearest adventurer, I am pleased to hear that you have performed well in the Ambuscade.
        AS_A_TOKEN_OF_MY_APPRECIATION_I_HAVE                                 = 8244,  -- As a token of my appreciation, I have prepared a new reward for your efforts. It is a material that I refer to as %.
        ALTHOUGH_THE_TECHNOLOGY_BEHIND_IT_MUST_REMAIN_SECRET                 = 8245,  -- Although the technology behind it must remain secret, it is able to upgrade equipment such as your %. However, you will need many of them to perform the upgrade.
        I_HAVE_LEFT_THE_DETAILS_WITH_MY_REPRESENTATIVE                       = 8246,  -- I have left the details with my representative at the A.M.A.N. Please check with him for more information.
        SIMPLY_GIVE_THE_AND_THE_ITEM_YOU_WISH                                = 8247,  -- Simply give the % and the item you wish to upgrade to my compatriot at the A.M.A.N. and he will bring out the very best in your equipment. I hope you will give it a try when you get a chance.
        MOMMY_DEAREST_HOW_HAVE_YOU_BEEN_I_AM                                 = 8248,  -- Mommy Dearest, How have you been? I am doing well.
        I_M_FINALLY_GETTING_USED_TO_MY_LIFE                                  = 8249,  -- I'm finally getting used to my life here in Mhaura. Rycharde is an excellentaru chef. In fact, Mhauran couscous is now one of my favorite dishes.
        I_M_STILL_HAVING_TROUBLE_AT_WORK_THOUGH                              = 8250,  -- I'm still having trouble at work though. The adventurers trying their hand at the Ambuscade are coming back with all kinds of cuts and scrapes-wapes, and sometimes in even worse shape. My days are definitely full of adventure.
        P_S_LATELY_I_VE_BEEN_HOOKED_WOOKED                                   = 8251,  -- P.S. Lately, I've been hooked-wooked on doing Cardian impressions. Personally, I think I've gotten pretty good at them.
        EVERYDAY_S_A_GRAND_SURPRISE_WHEN_YOU_TAKE                            = 8252,  -- Everyday's a grand surprise when you take part in an Ambuscade!
        DEAREST_ADVENTURER_THANKS_TO_YOUR_MOST_STEADFAST_EFFORTS             = 8253,  -- Dearest Adventurer, Thanks to your most steadfast efforts, I have accumulated a veritable treasure trove of data that will surely prove useful in my studies.
        BUT_LEST_YOU_THINK_MY_WORDS_HOLLOW_I                                 = 8254,  -- But lest you think my words hollow, I have prepared an even greater set of rewards in the form of %.
        THESE_AMAZING_MATERIALS_CAN_BE_USED_TO_AUGMENT                       = 8255,  -- These amazing materials can be used to augment equipment such as %. It should come as no surprise that you will need multiples of this fine new bounty in order to augment your attire.
        MOMMY_DEAREST_HOW_HAVE_YOU_BEEN_I_AM_2                               = 8256,  -- Mommy Dearest, How have you been? I am doing well.
        I_VE_HEARD_SOME_SCARY_TALES_OF_PIRATES                               = 8257,  -- I've heard some scary tales of pirates boarding innocent vessels that leave here from Mhaura. And you know what's even scarier? That this pleases the adventurers to no end!
        OF_COURSE_THIS_HAS_PROFOUNDLY_AFFECTED_WHAT_REMAINS                  = 8258,  -- Of course, this has profoundly affected what remains of my sanity, so I asked A.M.A.N. for a mental health leave. However, they denied my request, saying that hard work is the best medicine.
        P_S_PLEASE_SEND_COOKIES_THEY_MAY_BE                                  = 8259,  -- P.S. Please send cookies. They may be the only thing that gets me through the dark days ahead.
        WHICH_WOULD_YOU_LIKE_SULEVIA_S_PLATE_ARMOR                           = 8260,  -- Which would you like? Sulevia's plate armor. Hizamaru yoroi. Inyanga jubbah. Meghanada leather armor. Jhakri robe. Return to previous selection.
        WHICH_WOULD_YOU_LIKE_GO_BACK_RETURN_TO                               = 8261,  -- Which would you like? %. %. %. %. %. %. %. %. %. %. Go back. Return to previous selection.
        I_SEE_YOU_HAVE_CHOSEN_THE_A_FINE                                     = 8262,  -- I see you have chosen the %. A fine choice-woice, if you ask me. That will require % and # %.
        YOUR_ITEM_WILL_BE_THE_WHAT_DO_YOU                                    = 8263,  -- Your item will be the %. What do you think?
        WHICH_WOULD_YOU_LIKE_FLAMMA_KORAZIN_TALI_AH                          = 8264,  -- Which would you like? Flamma Korazin. Tali'ah Manteel Mummu Jacket. Ayanmo Corazza. Mallquis Saio. Go back.
        GREETINGS_AND_SALU_WALUTATIONS_TO_YOU_ADVENTURER_ALLOW               = 8265,  -- Greetings and salu-walutations to you, adventurer! Allow me to bestow a Signet on you as a token of thanks for your valiantaru efforts.
        DEAREST_ADVENTURER_DUE_TO_YOUR_MOST_REMARKABLE_EXPLOITS              = 8266,  -- Dearest Adventurer, Due to your most remarkable exploits in the Ambuscade, I have once again gleaned insights that will prove most valuable in my studies.
        AS_IS_MY_WONT_I_HAVE_PREPARED_FOR                                    = 8267,  -- As is my wont, I have prepared for you a most lavish reward in the form of weapons which I call %, and other arms in the same vein.
        I_HAVE_ALSO_READIED_FOR_YOUR_BENEFIT_AN                              = 8268,  -- I have also readied for your benefit an arcane metal of my own devising, %. While I cannot divulge the secrets behind this material, let it suffice to say that it will serve you in upgrading the aforementioned weapons, provided you are able to procure the requisite quantity.
        I_WOULD_ALSO_BE_REMISS_NOT_TO_INFORM                                 = 8269,  -- I would also be remiss not to inform you that these weapons are still under development. That is to say, I will require yet more battle data before I can refine them to reach their true potential. As such, I would most humbly entreat your continued cooperation.
        SIMPLY_DELIVER_THE_REQUISITE_QUANTITY_OF_AND_YOUR                    = 8270,  -- Simply deliver the requisite quantity of % and your weapon of choice to my compatriot at the A.M.A.N., and he will perform the necessary procedure to help unlock the item's latent powers. Do be sure to try it out, and evaluate for yourself its true potential.
        MOMMY_DEAREST_HOW_DO_YOU_FARE_I_AM                                   = 8271,  -- Mommy Dearest, How do you fare? I am doing quite well, thank you.
        THE_SHIPS_THAT_SET_FORTH_FROM_MHAURA_JOURNEY                         = 8272,  -- The ships that set forth from Mhaura journey-wourney to a faraway empire known as Aht Urhgan. I had a thoughtaru I would like to visit it myself someday, so I began researching it in detail.
        SADLY_MY_RESEARCH_FOUND_THAT_IT_IS_SO                                = 8273,  -- Sadly, my research found that it is so peri-werilous that even if I were to somehow make it there in one piece, a simple stroll outside town would likely be my lastaru! (Perhaps Abdhaljs would be willing to donate some of his spare armor for a worthy cause...)
